// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





function useComponent(props: Props) {
  // State for current display data
  // (props provide all data directly, so minimal state needed)

  // Memoize weather icon based on condition
  const weatherIcon = useMemo(() => {
    const condition = props.condition ? props.condition.toLowerCase() : '';
    if (condition.includes('sunny') || condition.includes('clear')) return '☀️';
    if (condition.includes('cloudy') || condition.includes('overcast')) return '☁️';
    if (condition.includes('rain')) return '🌧️';
    if (condition.includes('snow')) return '❄️';
    if (condition.includes('storm') || condition.includes('thunder')) return '⛈️';
    if (condition.includes('wind')) return '💨';
    if (condition.includes('fog') || condition.includes('mist')) return '🌫️';
    return '🌤️';
  }, [props.condition]);

  return {
    weatherIcon,
    city: props.city,
    temperature: props.temperature,
    condition: props.condition,
    humidity: props.humidity,
    windSpeed: props.windSpeed,
    unit: props.unit,
    forecast: props.forecast,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24} align="center">
        {/* HEADER — City and title */}
        <Stack gap={8} align="center">
          <Heading level={1}>{state.city}</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current Weather
          </Text>
        </Stack>

        {/* CURRENT CONDITIONS CARD */}
        <Card shadow="lg" padding={32} radius="lg" style={{ width: '100%', maxWidth: '400px' }}>
          <Stack gap={24} align="center">
            {/* Weather Icon and Temp */}
            <Stack gap={16} align="center">
              <Text size="4xl">{state.weatherIcon}</Text>
              <Stack gap={4} align="center">
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
                  {Math.round(state.temperature ?? 0)}°{state.unit || 'C'}
                </Text>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                  {state.condition}
                </Text>
              </Stack>
            </Stack>

            {/* Divider */}
            <Divider margin={0} />

            {/* Weather Details Grid */}
            <Row gap={16} justify="center" align="stretch" wrap>
              {/* Humidity */}
              <Box
                padding={12}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius={8}
                style={{ flex: '1 1 45%', minWidth: '100px', textAlign: 'center' }}
              >
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
                  {(state.humidity ?? 0)}%
                </Text>
              </Box>

              {/* Wind Speed */}
              <Box
                padding={12}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius={8}
                style={{ flex: '1 1 45%', minWidth: '100px', textAlign: 'center' }}
              >
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)" style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}>
                  {Math.round(state.windSpeed ?? 0)} km/h
                </Text>
              </Box>
            </Row>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST STRIP */}
        <Stack gap={12} style={{ width: '100%' }}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="semibold">
            5-Day Forecast
          </Text>
          <Row gap={8} justify="between" wrap>
            {state.forecast && state.forecast.length > 0 ? (
              state.forecast.map((day, idx) => (
                <Card
                  key={idx}
                  padding={12}
                  shadow="sm"
                  radius="md"
                  border
                  style={{
                    flex: '1 1 auto',
                    minWidth: '70px',
                    textAlign: 'center',
                  }}
                >
                  <Stack gap={8} align="center">
                    <Text variant="caption" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                      {day.day || `Day ${idx + 1}`}
                    </Text>
                    <Text size="2xl">{day.icon || '🌤️'}</Text>
                    <Box style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-1, 4px)', textAlign: 'center' }}>
                      <Text size="sm" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                        {day.high !== undefined ? Math.round(day.high) : '-'}°
                      </Text>
                      <Text size="sm" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {day.low !== undefined ? Math.round(day.low) : '-'}°
                      </Text>
                    </Box>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No forecast data available
              </Text>
            )}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

