// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





function useComponent(props: Props) {
  // State for form data and navigation
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // Validation helpers
  const validateEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  const validateStep = useCallback((step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!validateEmail(email)) {
        newErrors.email = 'Email must be valid';
      }
    } else if (step === 2) {
      if (!satisfaction) {
        newErrors.satisfaction = 'Please select a satisfaction rating';
      }
    } else if (step === 3) {
      if (features.length === 0) {
        newErrors.features = 'Please select at least one feature';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [name, email, satisfaction, features, validateEmail]);

  // Navigation handlers
  // Check if current step is valid before allowing next
  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      return name.trim() !== '' && email.trim() !== '' && validateEmail(email);
    }
    if (currentStep === 2) {
      return satisfaction !== '';
    }
    if (currentStep === 3) {
      return features.length > 0;
    }
    if (currentStep === 4) {
      return true; // Comments are optional
    }
    return true;
  }, [currentStep, name, email, satisfaction, features, validateEmail]);

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
      if (currentStep < 4) {
        setCurrentStep(currentStep + 1);
        setErrors({});
      } else {
        // Submit from review step
        const satisfactionNum = parseInt(satisfaction, 10);
        submit({
          name,
          email,
          satisfaction: satisfactionNum,
          features,
          comments
        });
      }
    }
  }, [currentStep, name, email, satisfaction, features, comments, validateStep, submit]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  }, [currentStep]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures(prev =>
      prev.includes(feature)
        ? prev.filter(f => f !== feature)
        : [...prev, feature]
    );
  }, []);

  // Memoized satisfaction options with guard for props
  const satisfactionOptions = useMemo(() => {
    if (!props.satisfactionLabels || props.satisfactionLabels.length === 0) {
      return [];
    }
    return props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label: `${index + 1} - ${label}`
    }));
  }, [props.satisfactionLabels]);
  return { submit, currentStep, setCurrentStep, name, setName, email, setEmail, satisfaction, setSatisfaction, features, setFeatures, comments, setComments, errors, handleNext, handleBack, handleFeatureToggle, satisfactionOptions, isStepValid };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Progress calculation
  const progressPercent = (state.currentStep / 4) * 100;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* PROGRESS BAR */}
        <Stack gap={8}>
          <Row justify="between" align="center">
            <Text variant="label">Step {state.currentStep} of 4</Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{Math.round(progressPercent)}%</Text>
          </Row>
          <Progress value={progressPercent} max={100} size="md" />
        </Stack>

        {/* HEADER */}
        <Stack gap={4}>
          <Heading level={2}>
            {state.currentStep === 1 && 'Contact Information'}
            {state.currentStep === 2 && 'Satisfaction Rating'}
            {state.currentStep === 3 && 'Feature Interests'}
            {state.currentStep === 4 && 'Additional Comments'}
          </Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {state.currentStep === 1 && 'Please provide your contact details.'}
            {state.currentStep === 2 && 'How satisfied are you with our service?'}
            {state.currentStep === 3 && 'Which features are you most interested in?'}
            {state.currentStep === 4 && 'Any additional feedback? (Optional)'}
          </Text>
        </Stack>

        {/* CONTENT */}
        <Card shadow="sm" padding={24}>
          <Stack gap={16}>
            {/* STEP 1: Contact Information */}
            {state.currentStep === 1 && (
              <Stack gap={16}>
                <Input
                  label="Name"
                  value={state.name}
                  onChange={state.setName}
                  placeholder="John Doe"
                  error={state.errors.name}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  value={state.email}
                  onChange={state.setEmail}
                  placeholder="john@example.com"
                  error={state.errors.email}
                  required
                />
              </Stack>
            )}

            {/* STEP 2: Satisfaction Rating */}
            {state.currentStep === 2 && (
              <RadioGroup
                label="How satisfied are you?"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                options={state.satisfactionOptions}
                direction="vertical"
                error={state.errors.satisfaction}
              />
            )}

            {/* STEP 3: Feature Interests */}
            {state.currentStep === 3 && (
              <Stack gap={12}>
                <Text variant="label">Which features interest you?</Text>
                <Stack gap={8}>
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={state.features.includes(feature)}
                      onChange={() => state.handleFeatureToggle(feature)}
                    />
                  ))}
                </Stack>
                {state.errors.features && (
                  <Text variant="caption" color="var(--ggui-color-error-500, #ef4444)">
                    {state.errors.features}
                  </Text>
                )}
              </Stack>
            )}

            {/* STEP 4: Comments */}
            {state.currentStep === 4 && (
              <TextArea
                label="Additional Comments"
                value={state.comments}
                onChange={state.setComments}
                placeholder="Tell us anything else you'd like us to know..."
                rows={6}
                maxLength={500}
                showCount
              />
            )}

            {/* STEP 4: Review - final review before submission */}
            {state.currentStep === 4 && state.comments !== '' && (
              <Stack gap={16}>
                <Stack gap={12}>
                  <Stack gap={4}>
                    <Text variant="label">Name</Text>
                    <Text variant="body">{state.name}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label">Email</Text>
                    <Text variant="body">{state.email}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label">Satisfaction Rating</Text>
                    <Text variant="body">
                      {state.satisfaction} - {props.satisfactionLabels[parseInt(state.satisfaction, 10) - 1]}
                    </Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label">Interested Features</Text>
                    <Stack gap={4} direction="horizontal" wrap>
                      {state.features.length > 0 ? (
                        state.features.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))
                      ) : (
                        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
                      )}
                    </Stack>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label">Comments</Text>
                    <Text variant="body">
                      {state.comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>
            )}
          </Stack>
        </Card>

        {/* FOOTER / ACTIONS */}
        <Row gap={12} justify="between">
          <Button
            variant="outline"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
           <Button
             variant="primary"
             onClick={state.handleNext}
             disabled={!state.isStepValid}
           >
              {state.currentStep === 4 && state.comments !== '' ? 'Submit' : 'Next'}
           </Button>
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




function useComponent(props: Props) {
  // State
  const [tasks, setTasks] = useState(props.tasks);
  const [addingTaskInColumn, setAddingTaskInColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');

  // Sync with props
  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Update tasks from stream events
  useEffect(() => {
    if (taskChanged.latest) {
      const event = taskChanged.latest;
      if (event.action === 'move' || event.action === 'edit') {
        setTasks((prev) => {
          const found = prev.findIndex((t) => t.id === event.task?.id);
          if (found >= 0) {
            const updated = [...prev];
            updated[found] = { ...updated[found], ...event.task };
            return updated;
          }
          return prev;
        });
      } else if (event.action === 'create' && event.task) {
        setTasks((prev) => [...prev, event.task!]);
      } else if (event.action === 'delete' && event.task?.id) {
        setTasks((prev) => prev.filter((t) => t.id !== event.task!.id));
      }
    }
  }, [taskChanged.latest]);

  // Summary stats
  const summary = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [tasks]);

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) => {
        const idx = prev.findIndex((t) => t.id === taskId);
        if (idx < 0) return prev;
        const updated = [...prev];
        updated[idx] = { ...updated[idx], column: newColumn };
        return updated;
      });
      taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    },
    [taskUpdate]
  );

  const handleAddTask = useCallback(
    () => {
      if (!newTaskTitle.trim()) return;
      const taskId = `task-${Date.now()}`;
      const newTask = {
        id: taskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: 'todo',
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId, data: { column: 'todo', title: newTaskTitle, priority: newTaskPriority } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingTaskInColumn(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      if (!newTitle.trim()) return;
      setTasks((prev) => {
        const idx = prev.findIndex((t) => t.id === taskId);
        if (idx < 0) return prev;
        const updated = [...prev];
        const taskColumn = updated[idx].column || 'todo';
        updated[idx] = { ...updated[idx], title: newTitle };
        return updated;
      });
      const foundTask = props.tasks.find((t) => t.id === taskId);
      const taskColumn = foundTask?.column || 'todo';
      taskUpdate({ action: 'edit', taskId, data: { column: taskColumn, title: newTitle } });
      setEditingTaskId(null);
      setEditingTaskTitle('');
    },
    [props.tasks, taskUpdate]
  );

  return { tasks, setTasks, summary, addingTaskInColumn, setAddingTaskInColumn, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, editingTaskId, setEditingTaskId, editingTaskTitle, setEditingTaskTitle, handleMoveTask, handleAddTask, handleEditTask, taskUpdate, taskChanged };
}

// Helper: get tasks for a column
function getTasksInColumn(tasks: Props['tasks'], columnId: string) {
  return tasks.filter((t) => t.column === columnId);
}

// Helper: priority badge color
function getPriorityVariant(priority?: string): 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info' {
  switch (priority) {
    case 'high':  return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
}

// Helper: get initials from assignee string
function getInitials(assignee?: string): string {
  if (!assignee) return '';
  return assignee.split(' ').map((w) => w.length > 0 && w[0]).filter(Boolean).join('').toUpperCase();
}

