}





function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<(typeof props.elements)[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [props.elements, searchQuery]);

  // Get unique categories from all elements
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  // Generate color tokens for each category
  const categoryColors = useMemo(() => {
    const colors: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
      'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
      'alkali-metal': 'var(--ggui-color-success-100, #dcfce7)',
      'alkaline-earth-metal': 'var(--ggui-color-success-200, #bbf7d0)',
      'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
      'post-transition-metal': 'var(--ggui-color-primary-200, #bae6fd)',
      'metalloid': 'var(--ggui-color-warning-200, #fde68a)',
      'nonmetal': 'var(--ggui-color-error-100, #fee2e2)',
      'lanthanide': 'var(--ggui-color-primary-300, #7dd3fc)',
      'actinide': 'var(--ggui-color-error-200, #fecaca)',
    };
    return colors;
  }, []);

  // Map category to text color
  const categoryTextColors = useMemo(() => {
    const colors: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-800, #155e75)',
      'halogen': 'var(--ggui-color-warning-800, #92400e)',
      'alkali-metal': 'var(--ggui-color-success-800, #166534)',
      'alkaline-earth-metal': 'var(--ggui-color-success-700, #15803d)',
      'transition-metal': 'var(--ggui-color-primary-800, #075985)',
      'post-transition-metal': 'var(--ggui-color-primary-700, #0369a1)',
      'metalloid': 'var(--ggui-color-warning-800, #92400e)',
      'nonmetal': 'var(--ggui-color-error-800, #991b1b)',
      'lanthanide': 'var(--ggui-color-primary-700, #0369a1)',
      'actinide': 'var(--ggui-color-error-700, #b91c1c)',
    };
    return colors;
  }, []);

  const handleElementClick = useCallback((element: typeof props.elements[0]) => {
    setSelectedElement(element);
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    categoryColors,
    categoryTextColors,
    handleElementClick,
  };
}
}

