// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





function useComponent(props: Props) {
  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const maxQuantity = props.product.stock || 0;
  const isOutOfStock = maxQuantity === 0;
  const stockStatus = maxQuantity > 10 ? 'In Stock' : maxQuantity > 0 ? 'Low Stock' : 'Out of Stock';
  const stockBadgeVariant = maxQuantity > 10 ? 'success' : maxQuantity > 0 ? 'warning' : 'error';
  const formattedPrice = props.product.price ? `${props.product.currency || '$'}${props.product.price.toFixed(2)}` : 'N/A';

  // Handlers
  const handleAddToCart = useCallback(() => {
    if (props.product.id && quantity > 0) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  const handleQuantityChange = useCallback((value: number) => {
    const newQty = Math.max(1, Math.min(value, maxQuantity));
    setQuantity(newQty);
  }, [maxQuantity]);

  const tabItems = useMemo(() => [
    { key: 'description', label: 'Description', content: <Text variant="body">{props.product.description || 'No description available'}</Text> },
    { key: 'specifications', label: 'Specifications', content: renderSpecifications(props.product.specifications) },
    { key: 'reviews', label: 'Reviews', content: renderReviews(props.product.reviews) },
  ], [props.product.description, props.product.specifications, props.product.reviews]);

  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  return { quantity, setQuantity, activeTab, setActiveTab, isOutOfStock, stockStatus, stockBadgeVariant, formattedPrice, handleAddToCart, handleQuantityChange, tabItems, addToCart };
}

// Helper: Render specifications table
function renderSpecifications(specs: unknown[] | undefined) {
  if (!specs || !Array.isArray(specs) || specs.length === 0) {
    return <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications available</Text>;
  }
  const specArray = specs as Array<{ key?: string; value?: string }>;
  const columns = [
    { key: 'key', header: 'Property', align: 'left' as const },
    { key: 'value', header: 'Value', align: 'left' as const },
  ];
  return <Table columns={columns} data={specArray.map((s, i) => ({ id: i, ...s }))} />;
}

// Helper: Render reviews list
function renderReviews(reviews: unknown[] | undefined) {
  if (!reviews || !Array.isArray(reviews) || reviews.length === 0) {
    return <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet</Text>;
  }
  const reviewArray = reviews as Array<{ author?: string; rating?: number; text?: string; date?: string }>;
  return (
    <Stack gap={12}>
      {reviewArray.map((review, i) => (
        <Card key={i} padding={16} shadow="sm" border={false}>
          <Stack gap={8}>
            <Row justify="between" align="center">
              <Text variant="label">{review.author || 'Anonymous'}</Text>
              <Stack direction="horizontal" gap={4} align="center">
                {[...Array(5)].map((_, j) => (
