                ))}
              </Stack>
            </Row>
            <Text variant="body">{review.text || 'No text provided'}</Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{review.date || 'N/A'}</Text>
          </Stack>
        </Card>
      ))}
    </Stack>
  );
}

