                    onClick={() => state.handleQuantityChange(state.quantity - 1)}
                    disabled={state.quantity <= 1 || state.isOutOfStock}
                  >
                    −
                  </Button>
                  <Box
                    style={{
                      minWidth: '40px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      padding: 'var(--ggui-spacing-1, 4px)',
                    }}
                  >
                    <Text variant="label" align="center">{state.quantity}</Text>
                  </Box>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => state.handleQuantityChange(state.quantity + 1)}
                    disabled={state.quantity >= state.maxQuantity || state.isOutOfStock}
                  >
                    +
                  </Button>
                </Stack>
              </Stack>

              <Button
                variant="primary"
                size="lg"
                fullWidth
                disabled={state.isOutOfStock}
                onClick={state.handleAddToCart}
              >
                {state.isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
              </Button>
            </Stack>
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

