import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




function useComponent(props: Props) {
  const [allMessages, setAllMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages]);

  // Append incoming messages to the list
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Handle typing indicator updates
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || null);
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  const handleKeyPress = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return { sendMessage, message, typing, allMessages, setAllMessages, inputValue, setInputValue, typingUser, handleSendMessage, handleKeyPress, messagesEndRef };
}

// Helper: Format timestamp to HH:MM
function formatTime(timestamp?: string): string {
  if (!timestamp) return '';
  try {
    return new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

// Helper: Group consecutive messages from same sender
function groupMessagesBySender(messages: Array<{ sender?: string; text?: string; timestamp?: string }>) {
  const groups: Array<{ sender?: string; messages: Array<{ text?: string; timestamp?: string }> }> = [];
  for (const msg of messages) {
    if (groups.length === 0 || groups[groups.length - 1].sender !== msg.sender) {
      groups.push({ sender: msg.sender, messages: [] });
    }
    groups[groups.length - 1].messages.push({ text: msg.text, timestamp: msg.timestamp });
  }
  return groups;
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const messageGroups = useMemo(() => groupMessagesBySender(state.allMessages), [state.allMessages]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        {/* HEADER */}
        <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="lg">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Row gap="var(--ggui-spacing-2, 8px)" align="center">
              <Heading level={2}>{props.title}</Heading>
              <Badge variant="primary" size="sm">{props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}</Badge>
            </Row>
            {state.typingUser && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.typingUser} is typing...</Text>
            )}
          </Stack>
        </Card>

        {/* MESSAGE LIST */}
        <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="lg" style={{ minHeight: '400px', maxHeight: '500px', overflowY: 'auto' }}>
          <Stack gap="var(--ggui-spacing-4, 16px)">
            {messageGroups.length === 0 ? (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">No messages yet. Start the conversation!</Text>
            ) : (
              messageGroups.map((group, groupIdx) => (
                <Stack key={groupIdx} gap="var(--ggui-spacing-2, 8px)" align={group.sender === props.currentUser ? 'end' : 'start'}>
                  {group.messages.map((msg, msgIdx) => (
                    <Box
                      key={msgIdx}
                      padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                      background={group.sender === props.currentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                      style={{ maxWidth: '60%' }}
                    >
                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        {msgIdx === 0 && (
                          <Text variant="label" color={group.sender === props.currentUser ? '#ffffff' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>{group.sender}</Text>
                        )}
                        <Text variant="body" color={group.sender === props.currentUser ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>{msg.text}</Text>
                        {msg.timestamp && (
                          <Text variant="caption" color={group.sender === props.currentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>{formatTime(msg.timestamp)}</Text>
                        )}
                      </Stack>
                    </Box>
                  ))}
                </Stack>
              ))
            )}
            <div ref={state.messagesEndRef} />
          </Stack>
        </Card>

        {/* INPUT AREA */}
        <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="lg">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <TextArea
              label="Message"
              value={state.inputValue}
              onChange={state.setInputValue}
              placeholder="Type your message...(Shift+Enter for new line)"
              rows={3}
              onKeyDown={state.handleKeyPress}
              disabled={false}
            />
            <Button
              variant="primary"
              size="md"
              onClick={state.handleSendMessage}
              disabled={!state.inputValue.trim()}
              fullWidth={false}
            >
              Send
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

