// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion, MotionKeyframes } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




function useComponent(props: Props) {
  // Merge initial stock data with live price updates
  const [displayStocks, setDisplayStocks] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [highlightedSymbol, setHighlightedSymbol] = useState<string | null>(null);

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // Update stocks when price updates arrive
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      if (update.symbol && update.price !== null && update.price !== undefined) {
        setDisplayStocks((prev) =>
          prev.map((stock) =>
            stock.symbol === update.symbol
              ? {
                  ...stock,
                  price: update.price ?? stock.price,
                  change: update.change ?? stock.change,
                  changePercent: update.changePercent ?? stock.changePercent,
                }
              : stock
          )
        );
        setLastUpdated(new Date());
        setHighlightedSymbol(update.symbol);
        const timer = setTimeout(() => setHighlightedSymbol(null), 600);
        return () => clearTimeout(timer);
      }
    }
  }, [priceUpdate.latest]);

  return { displayStocks, lastUpdated, highlightedSymbol, priceUpdate, marketStatus };
}

const StockCard = ({ stock, isHighlighted }: { stock: Props['stocks'][0]; isHighlighted: boolean }) => {
  const isPositive = (stock.changePercent ?? 0) >= 0;
  const borderColor = isPositive
    ? 'var(--ggui-color-success-500, #22c55e)'
    : 'var(--ggui-color-error-500, #ef4444)';
  const textColor = isPositive
    ? 'var(--ggui-color-success-600, #16a34a)'
    : 'var(--ggui-color-error-600, #dc2626)';

  const handleCardClick = () => {
    // TODO: Implement stock detail view or selection
  };

  return (
    <>
      <style>{`
        @keyframes ggui-flash {
          0% { background-color: var(--ggui-color-primary-100, #e0f2fe); }
          100% { background-color: transparent; }
        }
      `}</style>
      <Card
        as={Hoverable}
        onClick={handleCardClick}
        hoverStyle={{ opacity: 0.95 }}
        shadow="md"
        padding={20}
        border={true}
        radius="lg"
        style={{
          borderColor: borderColor,
          animation: isHighlighted ? 'ggui-flash 600ms ease-out' : 'none',
          transition: 'all 200ms ease-in-out',
          cursor: 'pointer',
        }}
      >
        <Stack gap={12}>
          <Stack gap={4}>
             <Heading level={3} color="var(--ggui-color-onSurface, #18181b)" style={{ fontWeight: 'bold' }}>
              {stock.symbol ?? 'N/A'}
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {stock.name ?? 'Unknown Company'}
            </Text>
          </Stack>

          <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                ${stock.price?.toFixed(2) ?? '0.00'}
              </Text>
              <Stack direction="horizontal" gap={4} align="center">
                <Text variant="bodySmall" weight="semibold" color={textColor}>
                  {isPositive ? '▲' : '▼'} {isPositive ? '+' : ''}{stock.change?.toFixed(2) ?? '0.00'} ({stock.changePercent?.toFixed(2) ?? '0.00'}%)
                </Text>
              </Stack>
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </>
  );
};

export default function Component(props: Props) {
  const state = useComponent(props);
  const [searchQuery, setSearchQuery] = useState('');

  const formattedTime = state.lastUpdated.toLocaleTimeString('en-US', {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });

  const marketStatusText = state.marketStatus.latest?.status ?? 'unknown';
  const marketStatusVariant =
    marketStatusText === 'open'
      ? 'success'
      : marketStatusText === 'closed'
        ? 'error'
        : 'warning';

  const filteredStocks = useMemo(() => {
    if (!state.displayStocks || state.displayStocks.length === 0) return [];
    return state.displayStocks.filter((stock) =>
      (stock.symbol ?? '').toLowerCase().includes(searchQuery.toLowerCase()) ||
      (stock.name ?? '').toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [state.displayStocks, searchQuery]);

  const handleRefresh = useCallback(() => {
    // Placeholder for manual refresh action
  }, []);

  return (
    <Container maxWidth="xl" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        {/* HEADER */}
        <Header
          logo={<Heading level={2} color="var(--ggui-color-onSurface, #18181b)">Market Watch</Heading>}
          actions={
            <Stack direction="horizontal" gap={12} align="center">
              <Stack gap={2} align="end">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated
                </Text>
                <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                  {formattedTime}
                </Text>
              </Stack>
              <Button variant="ghost" size="sm" onClick={handleRefresh}>
                Refresh
              </Button>
              <Badge variant={marketStatusVariant} size="sm">
                {marketStatusText.charAt(0).toUpperCase() + marketStatusText.slice(1)}
              </Badge>
            </Stack>
          }
        />

        {/* SEARCH FIELD */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder="Search by symbol or company name..."
          size="md"
        />

        {/* STOCK GRID */}
        {filteredStocks.length === 0 && state.displayStocks && state.displayStocks.length === 0 ? (
          <Alert variant="info" title="No Stocks">
            No stocks available to display.
          </Alert>
        ) : filteredStocks.length === 0 ? (
          <Alert variant="info" title="No Results">
            No stocks match your search query. Try adjusting your search terms.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={20}>
            {filteredStocks.map((stock) => (
              <StockCard
                key={stock.symbol ?? Math.random()}
                stock={stock}
                isHighlighted={state.highlightedSymbol === stock.symbol}
              />
            ))}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

