import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





function useComponent(props: Props) {
  const complete = useAction<ActionCompletePayload>('complete');

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications !== false,
    theme: props.initialProfile.theme || 'light',
  });

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isStep1Valid = formData.name.trim() && emailRegex.test(formData.email);
  const isStep2Valid = formData.role.trim();
  const canProceed = step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true;

  const handleNext = useCallback(() => {
    if (step < 3) setStep(step + 1);
  }, [step]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep(step - 1);
  }, [step]);

  const handleComplete = useCallback(() => {
    complete(formData);
  }, [formData, complete]);

  return { step, formData, setFormData, handleNext, handleBack, handleComplete, canProceed, isStep1Valid };
}

export default function Component(props: Props) {
  const { step, formData, setFormData, handleNext, handleBack, handleComplete, canProceed, isStep1Valid } = useComponent(props);

  return (
    <Container maxWidth='md' padding={24}>
      <Stack gap={24}>
        {/* PROGRESS INDICATOR */}
        <Stack gap={8}>
          <Row justify='between' align='center'>
            <Text variant='label'>Step {step} of 3</Text>
            <Text variant='label' color='var(--ggui-color-onSurfaceVariant, #52525b)'>{step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}</Text>
          </Row>
          <Progress value={step} max={3} size='md' />
        </Stack>

        {/* STEP 1: PROFILE SETUP */}
        {step === 1 && (
          <Stack gap={16}>
            <Heading level={2}>Profile Setup</Heading>
            <Input label='Name' required value={formData.name} onChange={(name) => setFormData({...formData, name})} placeholder='Enter your name' error={formData.name.trim() === '' ? 'Name is required' : ''} />
            <Input label='Email' required type='email' value={formData.email} onChange={(email) => setFormData({...formData, email})} placeholder='Enter your email' error={formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email) ? 'Valid email required' : ''} />
            <Stack gap={8}>
              <Text variant='label'>Avatar</Text>
              <Row gap={8} justify='start'>
                {props.avatarOptions.map((emoji) => (
                  <Box key={emoji} as={Clickable} onClick={() => setFormData({...formData, avatar: emoji})} style={{padding: 'var(--ggui-spacing-2, 8px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid transparent', cursor: 'pointer', fontSize: '24px', transition: 'all 200ms ease-in-out'}} hoverStyle={{transform: 'scale(1.1)'}}>
                    {emoji}
                  </Box>
                ))}
              </Row>
            </Stack>
          </Stack>
        )}

        {/* STEP 2: PREFERENCES */}
        {step === 2 && (
          <Stack gap={16}>
            <Heading level={2}>Preferences</Heading>
            <Select label='Role' required value={formData.role} onChange={(role) => setFormData({...formData, role})} options={props.roleOptions.map(r => ({value: r, label: r}))} placeholder='Select your role' />
            <Toggle label='Email Notifications' checked={formData.emailNotifications} onChange={(emailNotifications) => setFormData({...formData, emailNotifications})} />
            <Toggle label='Dark Theme' checked={formData.theme === 'dark'} onChange={(isDark) => setFormData({...formData, theme: isDark ? 'dark' : 'light'})} />
          </Stack>
        )}

        {/* STEP 3: REVIEW */}
        {step === 3 && (
          <Stack gap={16}>
            <Heading level={2}>Review & Confirm</Heading>
            <Card shadow='sm' padding={16}>
              <Stack gap={12}>
                <Box>
                  <Text variant='label'>Name</Text>
                  <Text>{formData.name}</Text>
                </Box>
                <Divider />
                <Box>
                  <Text variant='label'>Email</Text>
                  <Text>{formData.email}</Text>
                </Box>
                <Divider />
                <Box>
                  <Text variant='label'>Avatar</Text>
                  <Text>{formData.avatar}</Text>
                </Box>
                <Divider />
                <Box>
                  <Text variant='label'>Role</Text>
                  <Text>{formData.role}</Text>
                </Box>
                <Divider />
                <Box>
                  <Text variant='label'>Email Notifications</Text>
                  <Text>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                </Box>
                <Divider />
                <Box>
                  <Text variant='label'>Theme</Text>
                  <Text>{formData.theme === 'dark' ? 'Dark' : 'Light'}</Text>
                </Box>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* NAVIGATION */}
        <Row gap={8} justify='between'>
          <Button variant='ghost' onClick={handleBack} disabled={step === 1}>Go Back</Button>
          {step < 3 && <Button variant='primary' onClick={handleNext} disabled={!canProceed}>Next</Button>}
          {step === 3 && <Button variant='primary' onClick={handleComplete}>Complete Setup</Button>}
        </Row>
      </Stack>
    </Container>
  );
}
